import{_ as a,o as n,c as i,an as s}from"./chunks/framework.aORHsabP.js";const g=JSON.parse('{"title":"Changelog convention","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/changelog.md","filePath":"getting-started/changelog.md","lastUpdated":null}'),t={name:"getting-started/changelog.md"};function o(r,e,d,l,h,c){return n(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="changelog" tabindex="-1">Changelog convention <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog convention {#changelog}&quot;">​</a></h1><p><code>scaffold</code> seeds every package with a <code>NEWS.md</code> (package-owned, written once, never overwritten — see <a href="/previews/PR317/getting-started/infrastructure#infrastructure">Infrastructure and template sync</a>). This page is the org-wide convention for what goes in it, decided in <a href="https://github.com/EpiAware/EpiAwarePackageTools.jl/issues/286" target="_blank" rel="noreferrer">EpiAwarePackageTools#286</a> after an audit found four different shapes in use across the ecosystem.</p><p><a href="https://github.com/EpiAware/CensoredDistributions.jl/blob/main/NEWS.md" target="_blank" rel="noreferrer">CensoredDistributions.jl&#39;s <code>NEWS.md</code></a> is the reference; ModifiedDistributions.jl follows it closely. Match that shape in a new or updated entry.</p><h2 id="The-shape" tabindex="-1">The shape <a class="header-anchor" href="#The-shape" aria-label="Permalink to &quot;The shape {#The-shape}&quot;">​</a></h2><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Unreleased</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### Added</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A one-sentence-per-line description of the change, written for a user</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  reading the changelog rather than the diff. Closes</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">#123</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">https://github.com/OWNER/REPO/issues/123</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### Fixed</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ...</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## v0.2.0 - Some milestone</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### Breaking</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ...</span></span></code></pre></div><ul><li><p>One <code>## Unreleased</code> section at the top, holding every entry since the last release.</p></li><li><p><code>### &lt;category&gt;</code> subsections underneath it, added only when they have an entry: <code>Added</code>, <code>Fixed</code>, <code>Deprecated</code>, <code>Removed</code>, <code>Breaking</code> cover most changes, and a repo-specific category (CensoredDistributions.jl&#39;s &quot;AD gradient infrastructure&quot;) is fine when a change doesn&#39;t fit the standard set.</p></li><li><p>One sentence per line, matching the org&#39;s prose convention elsewhere.</p></li><li><p>A full Markdown link for the closing reference — <code>Closes [#123](https://github.com/OWNER/REPO/issues/123))</code> — not a bare <code>#123</code> or a lowercase inline <code>closes #123</code>, so the changelog is readable standalone (it renders on the docs site) as well as on GitHub.</p></li><li><p>At release, <code>## Unreleased</code> is renamed to the version heading (<code>## vX.Y.Z - &lt;short label&gt;</code>) and a fresh empty <code>## Unreleased</code> is added above it.</p></li></ul><h2 id="When-to-add-an-entry" tabindex="-1">When to add an entry <a class="header-anchor" href="#When-to-add-an-entry" aria-label="Permalink to &quot;When to add an entry {#When-to-add-an-entry}&quot;">​</a></h2><p>Add a bullet in the PR that makes the change, not after the fact. A change belongs in <code>NEWS.md</code> if a user of the package (not a contributor reading the diff) would want to know about it: a new public function, a behaviour change, a bug fix, a deprecation. Internal refactors, test-only changes, and CI/infrastructure updates usually don&#39;t need an entry.</p><p>This is advisory, not enforced by a quality gate — see <a href="https://github.com/EpiAware/EpiAwarePackageTools.jl/issues/286" target="_blank" rel="noreferrer">EpiAwarePackageTools#286</a> for the discussion of whether to add one later.</p><h2 id="Migrating-an-existing-NEWS.md" tabindex="-1">Migrating an existing NEWS.md <a class="header-anchor" href="#Migrating-an-existing-NEWS.md" aria-label="Permalink to &quot;Migrating an existing NEWS.md {#Migrating-an-existing-NEWS.md}&quot;">​</a></h2><p>The convention is a target for new entries, not a mandate to rewrite history. A repo whose <code>NEWS.md</code> predates this page keeps its existing entries as they are; write new entries in the shape above going forward. Backfilling old entries to match (adding <code>Closes</code> links, splitting a paragraph into per-category bullets) is a judgement call for that repo&#39;s maintainer, not something <code>update</code> will ever do for you — <code>NEWS.md</code> stays package-owned and untouched by sync.</p>`,11)])])}const k=a(t,[["render",o]]);export{g as __pageData,k as default};
